#!/usr/bin/perl
use strict;
use warnings;

print "Content-type: text/html\n\n";

my $comment = param('comment');

if ($comment) {
    print "<div>$comment</div>";
} else {
    print "No comment provided.";
}

sub clean_input {
    my $input = shift;
    $input =~ s/[^a-zA-Z0-9\s\.,!?\/\\\-]/ /g;
    return $input;
}

if (param('comment')) {
    my $cleaned_comment = clean_input(param('comment'));
    print "<div>$cleaned_comment</div>";
}